func waitForGenerateVariants(c generateHTTP, data json.RawMessage) (json.RawMessage, error) {
	variants := extractVariantObjects(data)
	if len(variants) == 0 {
		return data, nil
	}
	latest := make([]map[string]any, 0, len(variants))
	for _, v := range variants {
		id := stringAtAny(v, []string{"id"}, []string{"clip_id"})
		if id == "" {
			latest = append(latest, v)
			continue
		}
		current := v
		// PATCH(greptile #577 P1): bump poll cap from 30*2s=60s to 150*2s=300s.
		// Suno generations routinely complete in 60-180s; v5.5 (chirp-fenix) renders
		// can exceed 90s, leaving variants with empty audio_url at the old cap.
		// pickGenerateVariant penalizes empty audio_url by +1_000_000, so on cap
		// timeout the "best" pick degenerated to a duration tie-break.
		for i := 0; i < 150; i++ {
			raw, err := c.Get("/api/clip/"+id, nil)
			if err == nil {
				obj := unmarshalObject(raw)
				if len(obj) > 0 {
					current = obj
				}
				if stringAtAny(obj, []string{"audio_url"}, []string{"audioUrl"}) != "" {
					break
				}
			}
			time.Sleep(2 * time.Second)
		}
		latest = append(latest, current)
	}
	return mustJSON(latest), nil
}

func pickGenerateVariant(data json.RawMessage, pick string, targetLo, targetHi float64) json.RawMessage {
	if pick == "both" {
		return data
	}
	variants := extractVariantObjects(data)
	if len(variants) == 0 {
		return data
	}
	idx := 0
	switch pick {
	case "second":
		if len(variants) > 1 {
			idx = 1
		}
	case "best":
		bestScore := 1e18
		for i, v := range variants {
			score := durationDistance(clipDuration(v), targetLo, targetHi)
			if stringAtAny(v, []string{"audio_url"}, []string{"audioUrl"}) == "" {
				score += 1000000
			}
			if score < bestScore {
				bestScore = score
				idx = i
			}
		}
	}
	return mustJSON(variants[idx])
}
